function getPluralForm(count, options) {
	const penultimateDigit = Math.floor(count / 10) % 10;
	const lastDigit = count % 10;
	let pluralForm = options.many;
	if (penultimateDigit !== 1 && lastDigit > 1 && lastDigit < 5) pluralForm = options.few;
	else if (penultimateDigit !== 1 && lastDigit === 1) pluralForm = options.one;
	return `${count} ${pluralForm}`;
}
